import type { Metadata } from 'next';
import { notFound } from 'next/navigation';

interface Props {
    params:      { slug: string };
    searchParams: { [key: string]: string | string[] };
}

// 動的メタデータ
export async function generateMetadata({ params }: Props): Promise<Metadata> {
    const post = await getPost(params.slug);
    if (!post) return { title: 'Not Found' };
    return {
        title:       post.title,
        description: post.excerpt,
    };
}

// 静的パスの事前生成（SSG）
export async function generateStaticParams() {
    const posts = await getAllPosts();
    return posts.map(p => ({ slug: p.slug }));
}

// Page コンポーネント（Server Component がデフォルト）
export default async function PostPage({ params, searchParams }: Props) {
    const post = await getPost(params.slug);
    if (!post) notFound();  // not-found.tsx を表示

    return <article>{post.content}</article>;
}

import Link from 'next/link';
import { useRouter, usePathname, useSearchParams } from 'next/navigation';
import { redirect } from 'next/navigation';

// Link コンポーネント（プリフェッチ自動）
function Nav() {
    const pathname = usePathname();
    return (
        <nav>
            <Link href="/">ホーム</Link>
            <Link href="/blog" prefetch={false}>ブログ</Link>
            <Link href={{ pathname: '/blog', query: { page: 2 } }}>2ページ</Link>
            {/* アクティブリンク */}
            <Link href="/about" className={pathname === '/about' ? 'active' : ''}>
                About
            </Link>
        </nav>
    );
}

// useRouter（Client Component のみ）
'use client';
function SearchButton() {
    const router = useRouter();
    return (
        <button onClick={() => {
            router.push('/search');         // 遷移
            router.replace('/search');      // 履歴を置き換え
            router.back();                  // 前のページ
            router.refresh();              // Server Component を再フェッチ
        }}>検索</button>
    );
}

// redirect（Server Component）
async function ProtectedPage() {
    const session = await getSession();
    if (!session) redirect('/login');  // ログインページへ
    return <Dashboard />;
}
